(
    link `String`
) engine = MergeTree
order by link;

CREATE PROVIDER open_ai_provider
ENGINE = OpenAI(
	api_key='sk-proj-xxx',
	model_name = 'gpt-4o-mini'
);

CREATE EMBEDDING MODEL IF NOT EXISTS generate_embeddings(
input COMMENT 'This is the input of the content whose embeddings are created'
) USING open_ai_provider(embedding_model='text-embedding-ada-002', encoding_format='float', dimensions=100)

CREATE MODEL retrieval_evaluator (
    question,
    document
) USING open_ai_provider()
PROMPT ( system "
Given a question, does the following document have exact
information to answer the question?
Question: {{question}}
Document: {{document}}
Think Step by step, and answer with yes or no only");

CREATE VIEW get_correct_documents(question String) AS 
 (with tbl as (
    select id, content, retrieval_evaluator($question, content) answer from pdf_contents
)
select id, answer, content
from tbl where positionCaseInsensitive(answer, 'yes') > 0);

CREATE MODEL evaluator(
    question,
    answer,
    score
) USING open_ai_provider()
PROMPT (system "Given a question and possible answer respond if it is relevant or not. 
Answer 'yes' if the score is below 0.1. If score is not provided, return 'no'.
Please use 'yes' or 'no' as the answer. 
question: {{question}}
possible answer: {{answer}}
similarity score: {{score}}");

CREATE TABLE cities_links (
	`city` "String",
	`link` "String"
) engine = MergeTree
order by city;

INSERT INTO cities_pdf(content, metadata, city) 
SELECT content, metadata, JSONExtractString(metadata,'city')
FROM load_pdf_text((SELECT link, city from cities_links));

